import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Base64;

import java.security.Key;
import java.security.KeyStore;

public class LocationEncryptor {
    private static final String KEY_ALIAS = "location_key";
    private static final String KEYSTORE_NAME = "AndroidKeyStore";

    public static String encryptLocation(Location location) throws Exception {
        // Generate a key pair
        KeyGenParameterSpec spec = new KeyGenParameterSpec.Builder(KEY_ALIAS, KeyProperties.PURPOSE_ENCRYPT)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_RSA_OAEP)
                .build();
        KeyStore keyStore = KeyStore.getInstance(KEYSTORE_NAME);
        keyStore.load(null);
        Key key = keyStore.getKey(KEY_ALIAS, null);

        // Encrypt the location data
        byte[] encryptedData = encrypt(location.getLatitude(), location.getLongitude(), key);

        // Return the encrypted data as a base64-encoded string
        return Base64.encodeToString(encryptedData, Base64.NO_WRAP);
    }

    private static byte[] encrypt(double latitude, double longitude, Key key) throws Exception {
        // Create a cipher instance
        Cipher cipher = Cipher.getInstance("RSA/ECB/OAEPWithSHA-256AndMGF1Padding");
        cipher.init(Cipher.ENCRYPT_MODE, key);

        // Encrypt the location data
        byte[] encryptedData = cipher.doFinal((latitude + "," + longitude).getBytes());

        return encryptedData;
    }
}
```
